INSERT INTO public.sentences (german, translation_en, level, mode, language, chapter, lesson) VALUES
('The left main coronary artery usually divides into the left anterior descending and left circumflex arteries.', 'The LAD mainly supplies the anterior wall, anterior septum, and apex, whereas the LCx supplies much of the lateral and posterolateral left ventricle.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('The LAD supplies the anterior two-thirds of the interventricular septum.', 'A proximal LAD occlusion can therefore produce extensive anterior and septal ischemia with major conduction and pump consequences.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('The posteromedial papillary muscle usually has a single arterial supply from the posterior descending artery.', 'Its limited collateral supply makes it particularly vulnerable to rupture after an inferior myocardial infarction.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Coronary dominance is defined by the artery that gives rise to the posterior descending artery.', 'Right dominance means the PDA arises from the RCA, whereas left dominance means it arises from the LCx.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A proximal RCA occlusion in a right-dominant circulation can threaten both the inferior left ventricle and the AV node.', 'Inferior infarction may therefore be complicated by bradycardia or heart block.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Left-ventricular coronary perfusion occurs predominantly during diastole.', 'Systolic compression of intramyocardial vessels makes tachycardia especially harmful because it shortens diastolic perfusion time.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Myocardial ischemia develops when oxygen demand exceeds coronary oxygen delivery.', 'The imbalance may result from obstructed flow, reduced oxygen content, reduced perfusion pressure, or excessive demand.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Tachycardia simultaneously increases myocardial oxygen demand and reduces diastolic coronary perfusion time.', 'This double effect can precipitate ischemia even without a new coronary occlusion.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Myocardial oxygen demand is determined mainly by heart rate, contractility, and ventricular wall stress.', 'Therapies that reduce these variables can relieve ischemic symptoms.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('According to Laplace principles, ventricular wall stress rises with chamber pressure and radius.', 'Hypertension, aortic stenosis, and ventricular dilation therefore increase myocardial oxygen consumption.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Severe anemia or hypoxemia can cause myocardial ischemia despite patent epicardial coronary arteries.', 'Reduced arterial oxygen content is an important cause of supply-demand mismatch.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Endothelial dysfunction reduces nitric-oxide bioavailability and promotes vasoconstriction, inflammation, and thrombosis.', 'Smoking, hypertension, diabetes, and dyslipidemia accelerate this process.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Apolipoprotein B-containing particles become trapped and modified within the arterial intima.', 'Macrophage uptake of modified lipids produces foam cells and initiates atherosclerotic plaque formation.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('A stable atherosclerotic plaque usually has a thick fibrous cap and relatively small lipid core.', 'It commonly causes predictable exertional angina through fixed luminal narrowing.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A vulnerable plaque has a thin fibrous cap, large necrotic core, and intense inflammation.', 'Rupture or erosion can expose thrombogenic material and trigger an acute coronary syndrome.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Platelet activation in ACS is amplified by ADP and thromboxane A2.', 'Platelet aggregation through glycoprotein IIb/IIIa receptors and fibrin formation stabilizes the coronary thrombus.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Persistent coronary occlusion causes irreversible myocardial necrosis that begins in the subendocardium.', 'With ongoing ischemia, injury progresses outward toward the epicardium in a wavefront pattern.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Malignant ventricular arrhythmias are an early complication of acute myocardial infarction.', 'Electrical instability is a major cause of sudden death during the first 24 hours.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Neutrophilic infiltration predominates approximately one to three days after myocardial infarction.', 'This stage is associated with acute inflammation and may produce fibrinous pericarditis.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Macrophages remove necrotic myocardium during the first one to two weeks after infarction.', 'The weakened wall during this period is vulnerable to free-wall, septal, or papillary-muscle rupture.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A healed myocardial infarction becomes a dense collagenous scar over weeks to months.', 'Late complications include scar-related arrhythmia, ventricular aneurysm, mural thrombus, and chronic heart failure.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Chronic coronary syndrome usually results from a stable fixed stenosis that limits coronary flow reserve.', 'Resting flow may be adequate, but exertion raises demand beyond the maximum flow available across the lesion.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Typical angina has three features: retrosternal discomfort, provocation by exertion or emotional stress, and relief with rest or short-acting nitrates.', 'All three features define typical angina; two suggest atypical angina.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Women, older adults, and patients with diabetes or chronic kidney disease may present with anginal equivalents.', 'Exertional dyspnea, fatigue, nausea, or epigastric discomfort may occur without classic chest pain.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('CCS class IV angina occurs with minimal activity or at rest.', 'This grade represents severe functional limitation and warrants urgent reassessment.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A resting ECG may be normal between episodes of stable angina.', 'A normal resting tracing does not exclude chronic coronary disease.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Troponin is generally normal in stable chronic coronary syndrome.', 'It is used to identify acute myocardial injury when symptoms become prolonged, severe, or otherwise concerning for ACS.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Exercise-induced horizontal or downsloping ST depression supports inducible myocardial ischemia.', 'Exercise ECG is less useful when the baseline ECG is already uninterpretable.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Stress echocardiography detects new or worsening regional wall-motion abnormalities.', 'Nuclear perfusion imaging distinguishes reversible ischemia from fixed scar.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Pharmacologic coronary vasodilators can reveal ischemia through coronary steal physiology.', 'Normal vascular beds dilate, diverting relative flow away from diseased territories that are already maximally dilated.', 'expert', 'medical', 'en', 'Cardiology', 'IHD'),
('Coronary CT angiography provides non-invasive visualization of coronary anatomy and plaque.', 'It is useful for excluding obstructive coronary disease in appropriately selected patients.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Invasive coronary angiography is the reference standard for defining coronary anatomy.', 'It is generally reserved for high-risk findings, severe symptoms, or planned revascularization.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Fractional flow reserve assesses the physiological significance of an intermediate coronary stenosis.', 'It helps distinguish lesions that restrict flow from those that appear narrow but are not functionally important.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('High-intensity statin therapy is disease-modifying in chronic coronary disease.', 'It lowers LDL cholesterol, reduces vascular inflammation, and stabilizes atherosclerotic plaque.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Beta-blockers relieve stable angina by lowering heart rate and contractility.', 'They reduce oxygen demand and prolong diastolic coronary perfusion time.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Nitrates reduce angina primarily by venodilation and reduction of preload.', 'Lower ventricular filling pressure reduces wall stress and myocardial oxygen demand.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Ranolazine reduces intracellular calcium-related diastolic tension without substantially lowering heart rate or blood pressure.', 'It can be useful when conventional antianginal therapy is inadequate or poorly tolerated.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('PCI is often favored for focal, less complex coronary disease.', 'CABG is generally preferred for left-main disease or complex multivessel disease, particularly in many patients with diabetes.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Variant angina results from transient epicardial coronary vasospasm.', 'It often occurs at rest and can produce transient ST-segment elevation.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Calcium-channel blockers and nitrates are central therapies for vasospastic angina.', 'Nonselective beta-blockade may worsen vasospasm by leaving alpha-mediated vasoconstriction relatively unopposed.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Microvascular angina can produce objective ischemia without flow-limiting epicardial stenosis.', 'Impaired small-vessel dilation or abnormal microvascular constriction may explain the symptoms.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Acute coronary syndromes usually result from plaque rupture or erosion with superimposed thrombosis.', 'The resulting obstruction may be complete, subtotal, intermittent, or associated with distal microembolization.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A 12-lead ECG should be obtained rapidly in suspected ACS.', 'Persistent ST elevation directs the patient toward an immediate reperfusion pathway.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A non-diagnostic initial ECG does not exclude ACS.', 'Serial ECGs are required when ischemic symptoms continue or recur.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Acute myocardial infarction requires a rise and/or fall in cardiac troponin with at least one value above the assay-specific 99th percentile plus evidence of ischemia.', 'A chronically stable troponin elevation alone does not establish acute MI.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Troponin measurement must not delay reperfusion in a patient with a diagnostic STEMI.', 'STEMI is an ECG-driven emergency in which myocardium is salvaged by rapid restoration of flow.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Unstable angina causes acute ischemic symptoms without biomarker-defined myocardial necrosis.', 'Troponin remains negative, although transient ST depression or T-wave inversion may occur.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('NSTEMI produces myocardial necrosis without persistent ST-segment elevation.', 'Diagnosis requires dynamic troponin elevation in the clinical context of ischemia.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('STEMI usually reflects acute complete or near-complete epicardial coronary occlusion.', 'Persistent ST elevation in anatomically contiguous leads indicates severe transmural ischemia and requires emergency reperfusion.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Aspirin and a P2Y12 inhibitor provide dual antiplatelet therapy in ACS.', 'These drugs inhibit platelet activation and reduce recurrent thrombosis and stent-related events.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Parenteral anticoagulation limits fibrin propagation during the acute phase of ACS.', 'It complements antiplatelet therapy but does not replace it.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Nitrates should be avoided in hypotension, right-ventricular infarction, or recent phosphodiesterase-5 inhibitor use.', 'Further preload reduction in these settings can produce profound hemodynamic collapse.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Primary PCI is the preferred reperfusion strategy for STEMI when it can be delivered promptly.', 'The source uses a door-to-balloon target below 90 minutes for an experienced PCI-capable center.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Fibrinolysis is an alternative for eligible early STEMI when timely PCI is unavailable.', 'It is generally considered within 12 hours of symptom onset after excluding major bleeding contraindications.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Very high-risk NSTE-ACS requires an immediate invasive strategy.', 'Cardiogenic shock, instability, refractory ischemia, malignant ventricular arrhythmia, or mechanical complications justify urgent angiography.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Type 1 myocardial infarction is caused by acute atherothrombosis after plaque rupture or erosion.', 'It is the classic spontaneous coronary infarction mechanism.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Type 2 myocardial infarction results from oxygen supply-demand imbalance without acute atherothrombosis.', 'Severe anemia, hypoxemia, hypotension, tachyarrhythmia, vasospasm, or severe hypertension may cause it.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Type 3 myocardial infarction describes ischemic cardiac death before biomarkers can be measured or rise.', 'Clinical or ECG evidence must strongly suggest acute ischemia.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Type 4 myocardial infarction is associated with PCI, whereas type 5 is associated with CABG.', 'The classification identifies the procedural context of myocardial injury and infarction.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Inferior STEMI produces ST elevation in leads II, III, and aVF.', 'Right-sided lead V4R should be obtained when right-ventricular infarction is suspected.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Posterior myocardial infarction may appear as reciprocal ST depression with tall R waves in V1 to V3.', 'Posterior leads V7 to V9 can reveal direct ST elevation.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Papillary-muscle rupture causes acute severe mitral regurgitation, pulmonary edema, and shock.', 'It most often affects the posteromedial papillary muscle several days after infarction.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Ventricular septal rupture produces a new harsh holosystolic murmur and left-to-right shunt.', 'A step-up in right-ventricular oxygen saturation supports the diagnosis.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Left-ventricular free-wall rupture causes hemopericardium, tamponade, and pulseless electrical activity.', 'It is a catastrophic mechanical complication during the period of maximal tissue weakness.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Dressler syndrome is a delayed autoimmune pericarditis after myocardial infarction.', 'It usually appears weeks after infarction rather than during the first few days.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('A true ventricular aneurysm contains scarred myocardial wall and typically does not rupture.', 'It may cause persistent ST elevation, mural thrombus, heart failure, or ventricular arrhythmia.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Long-term antiplatelet therapy is standard in established chronic coronary disease when bleeding risk is acceptable.', 'After ACS or PCI, dual therapy duration is individualized according to ischemic and bleeding risk.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('ACE inhibitors or ARBs are especially valuable after MI when reduced ejection fraction, anterior infarction, hypertension, diabetes, or chronic kidney disease is present.', 'They reduce maladaptive ventricular remodeling and improve long-term protection.', 'core', 'medical', 'en', 'Cardiology', 'IHD'),
('Primary-prevention ICD decisions are deferred until ventricular function has had time to recover after MI or revascularization.', 'The source describes reassessment after at least 40 days post-MI and three months post-revascularization.', 'advanced', 'medical', 'en', 'Cardiology', 'IHD'),
('Cardiac rehabilitation combines supervised exercise, risk-factor control, education, and psychosocial support.', 'Participation improves functional capacity and reduces recurrent cardiovascular morbidity.', 'core', 'medical', 'en', 'Cardiology', 'IHD');
INSERT INTO public.words (german, translation, level, mode, category, chapter, lesson) VALUES
('Coronary dominance', 'Classification based on which coronary artery gives rise to the posterior descending artery.', 'core', 'medical', 'Coronary Anatomy', 'Cardiology', 'IHD'),
('Posterior descending artery', 'The artery supplying the inferior-posterior ventricular territory and posterior interventricular septum.', 'core', 'medical', 'Coronary Anatomy', 'Cardiology', 'IHD'),
('Coronary flow reserve', 'The capacity of coronary blood flow to increase above resting levels in response to greater myocardial demand.', 'advanced', 'medical', 'Perfusion Physiology', 'Cardiology', 'IHD'),
('Myocardial oxygen demand', 'The oxygen requirement of the heart, determined mainly by heart rate, contractility, and wall stress.', 'core', 'medical', 'Perfusion Physiology', 'Cardiology', 'IHD'),
('Subendocardium', 'The inner myocardial layer, which is most vulnerable to ischemia because of high wall stress and limited perfusion.', 'core', 'medical', 'Pathophysiology', 'Cardiology', 'IHD'),
('Endothelial dysfunction', 'Loss of normal vasodilatory, antithrombotic, and anti-inflammatory endothelial functions.', 'core', 'medical', 'Atherosclerosis', 'Cardiology', 'IHD'),
('Foam cell', 'A lipid-laden macrophage formed after uptake of modified lipoproteins within the arterial intima.', 'core', 'medical', 'Atherosclerosis', 'Cardiology', 'IHD'),
('Fibrous cap', 'The collagen-rich layer that separates the blood from the lipid and necrotic core of an atherosclerotic plaque.', 'advanced', 'medical', 'Atherosclerosis', 'Cardiology', 'IHD'),
('Vulnerable plaque', 'An inflamed plaque with a thin cap and large necrotic core that is prone to rupture or erosion.', 'core', 'medical', 'Atherosclerosis', 'Cardiology', 'IHD'),
('Plaque erosion', 'Loss of the endothelial layer with exposure of thrombogenic subendothelial matrix without a deep cap rupture.', 'advanced', 'medical', 'Atherosclerosis', 'Cardiology', 'IHD'),
('Plaque rupture', 'Tearing of a plaque''s fibrous cap with exposure of the necrotic core and tissue factor.', 'core', 'medical', 'Atherosclerosis', 'Cardiology', 'IHD'),
('Coronary thrombosis', 'Formation of a platelet- and fibrin-rich clot within a coronary artery.', 'core', 'medical', 'ACS', 'Cardiology', 'IHD'),
('Chronic coronary syndrome', 'Stable coronary disease characterized by predictable ischemia, commonly from fixed atherosclerotic narrowing.', 'core', 'medical', 'Chronic Coronary Disease', 'Cardiology', 'IHD'),
('Typical angina', 'Retrosternal discomfort provoked by exertion or stress and relieved by rest or short-acting nitrates.', 'core', 'medical', 'Clinical Presentation', 'Cardiology', 'IHD'),
('Anginal equivalent', 'An ischemic symptom such as dyspnea, fatigue, nausea, or epigastric discomfort occurring without classic chest pain.', 'core', 'medical', 'Clinical Presentation', 'Cardiology', 'IHD'),
('Canadian Cardiovascular Society class', 'A four-level scale describing the degree of activity limitation caused by angina.', 'core', 'medical', 'Clinical Assessment', 'Cardiology', 'IHD'),
('Coronary steal', 'Relative diversion of blood toward normal vasodilated beds and away from diseased territories during pharmacologic stress.', 'expert', 'medical', 'Stress Testing', 'Cardiology', 'IHD'),
('Reversible perfusion defect', 'A stress-induced perfusion abnormality that normalizes at rest and indicates inducible ischemia.', 'advanced', 'medical', 'Imaging', 'Cardiology', 'IHD'),
('Fixed perfusion defect', 'A persistent perfusion abnormality at rest and stress that usually represents myocardial scar.', 'advanced', 'medical', 'Imaging', 'Cardiology', 'IHD'),
('Coronary CT angiography', 'A non-invasive anatomical test that displays the coronary lumen and plaque burden.', 'core', 'medical', 'Imaging', 'Cardiology', 'IHD'),
('Fractional flow reserve', 'An invasive pressure-derived index used to determine whether a coronary stenosis limits myocardial blood flow.', 'advanced', 'medical', 'Coronary Physiology', 'Cardiology', 'IHD'),
('Percutaneous coronary intervention', 'Catheter-based coronary revascularization, usually using balloon angioplasty and stent placement.', 'core', 'medical', 'Revascularization', 'Cardiology', 'IHD'),
('Coronary artery bypass grafting', 'Surgical revascularization using grafts to bypass obstructed coronary segments.', 'core', 'medical', 'Revascularization', 'Cardiology', 'IHD'),
('Variant angina', 'Episodic myocardial ischemia caused by transient epicardial coronary vasospasm, often occurring at rest.', 'core', 'medical', 'Special Syndromes', 'Cardiology', 'IHD'),
('INOCA', 'Ischemia with non-obstructive coronary arteries, commonly caused by microvascular dysfunction or vasospasm.', 'advanced', 'medical', 'Special Syndromes', 'Cardiology', 'IHD'),
('Acute coronary syndrome', 'A spectrum of unstable coronary ischemic syndromes including unstable angina, NSTEMI, and STEMI.', 'core', 'medical', 'ACS', 'Cardiology', 'IHD'),
('Unstable angina', 'Acute ischemia without biomarker-defined myocardial necrosis.', 'core', 'medical', 'ACS', 'Cardiology', 'IHD'),
('NSTEMI', 'Myocardial infarction with dynamic biomarker elevation but without persistent ST-segment elevation.', 'core', 'medical', 'ACS', 'Cardiology', 'IHD'),
('STEMI', 'Acute myocardial infarction with persistent ST elevation or an equivalent occlusion pattern requiring urgent reperfusion.', 'core', 'medical', 'ACS', 'Cardiology', 'IHD'),
('High-sensitivity cardiac troponin', 'A sensitive and specific biomarker used to detect acute myocardial injury through a rise-and-fall pattern.', 'core', 'medical', 'Biomarkers', 'Cardiology', 'IHD'),
('Dual antiplatelet therapy', 'Combined aspirin and P2Y12-receptor inhibition used after ACS or PCI.', 'core', 'medical', 'Pharmacology', 'Cardiology', 'IHD'),
('P2Y12 inhibitor', 'An antiplatelet drug class including clopidogrel, prasugrel, and ticagrelor.', 'core', 'medical', 'Pharmacology', 'Cardiology', 'IHD'),
('Primary PCI', 'Emergency catheter-based reperfusion used as the preferred treatment for STEMI when available promptly.', 'core', 'medical', 'Reperfusion', 'Cardiology', 'IHD'),
('Fibrinolysis', 'Pharmacologic dissolution of an acute coronary thrombus when timely primary PCI is unavailable in an eligible STEMI patient.', 'core', 'medical', 'Reperfusion', 'Cardiology', 'IHD'),
('Type 1 myocardial infarction', 'Spontaneous infarction caused by acute atherothrombotic plaque disruption.', 'core', 'medical', 'MI Classification', 'Cardiology', 'IHD'),
('Type 2 myocardial infarction', 'Infarction caused by myocardial oxygen supply-demand imbalance without acute atherothrombosis.', 'core', 'medical', 'MI Classification', 'Cardiology', 'IHD'),
('Type 3 myocardial infarction', 'Ischemic cardiac death occurring before biomarkers can be obtained or become elevated.', 'advanced', 'medical', 'MI Classification', 'Cardiology', 'IHD'),
('Type 4 myocardial infarction', 'Myocardial infarction associated with PCI or stent-related events.', 'advanced', 'medical', 'MI Classification', 'Cardiology', 'IHD'),
('Type 5 myocardial infarction', 'Myocardial infarction associated with CABG surgery.', 'advanced', 'medical', 'MI Classification', 'Cardiology', 'IHD'),
('Contraction-band necrosis', 'Hypercontracted eosinophilic myofibers caused by calcium influx and free-radical injury during reperfusion.', 'expert', 'medical', 'Histopathology', 'Cardiology', 'IHD'),
('Papillary-muscle rupture', 'Post-infarction mechanical failure causing acute severe mitral regurgitation.', 'core', 'medical', 'Complications', 'Cardiology', 'IHD'),
('Ventricular septal rupture', 'Post-infarction septal defect producing an acute left-to-right shunt.', 'core', 'medical', 'Complications', 'Cardiology', 'IHD'),
('Free-wall rupture', 'Post-infarction tearing of the ventricular wall causing hemopericardium and cardiac tamponade.', 'core', 'medical', 'Complications', 'Cardiology', 'IHD'),
('Dressler syndrome', 'Delayed autoimmune pericarditis developing weeks after myocardial infarction.', 'core', 'medical', 'Complications', 'Cardiology', 'IHD'),
('True ventricular aneurysm', 'Outward bulging of a thinned scarred ventricular wall that may cause thrombus, heart failure, or arrhythmia.', 'advanced', 'medical', 'Complications', 'Cardiology', 'IHD'),
('Cardiac rehabilitation', 'A structured secondary-prevention program combining exercise, risk-factor modification, education, and psychosocial care.', 'core', 'medical', 'Secondary Prevention', 'Cardiology', 'IHD');
INSERT INTO public.dialogues (title_de, title_en, level, mode, lines, chapter, lesson) VALUES
('Exertional Chest Pressure', 'Recognizing typical stable angina.', 'core', 'medical', '[{"speaker":"Attending","german":"A patient reports central pressure while climbing stairs that resolves after five minutes of rest. Which angina criteria are present?","translation_en":"Retrosternal discomfort, exertional provocation, and relief with rest are all present."},{"speaker":"Resident","german":"This meets all three criteria for typical angina.","translation_en":"The pattern is consistent with chronic coronary syndrome."},{"speaker":"Attending","german":"Would a normal resting ECG exclude the diagnosis?","translation_en":"No. The ECG may be normal between ischemic episodes."},{"speaker":"Resident","german":"Further testing should assess obstructive disease or inducible ischemia according to the patient''s risk and ECG interpretability.","translation_en":"Anatomical and functional testing are selected individually."}]'::jsonb, 'Cardiology', 'IHD'),
('Silent Ischemia in Diabetes', 'Identifying an anginal equivalent.', 'core', 'medical', '[{"speaker":"Resident","german":"A patient with diabetes develops exertional dyspnea and nausea but denies chest pain.","translation_en":"Diabetes may blunt pain perception through autonomic neuropathy."},{"speaker":"Attending","german":"Should ischemia still be considered?","translation_en":"Yes. Dyspnea, fatigue, nausea, and epigastric discomfort can be anginal equivalents."},{"speaker":"Resident","german":"I will assess the timing, triggers, cardiovascular risk, ECG, and evidence of acute injury.","translation_en":"Atypical presentation must not delay evaluation."}]'::jsonb, 'Cardiology', 'IHD'),
('STEMI Before Troponin', 'Reperfusion must not wait for biomarkers.', 'core', 'medical', '[{"speaker":"Resident","german":"The ECG shows persistent ST elevation in contiguous anterior leads, but the first troponin result is pending.","translation_en":"The ECG is diagnostic of an acute occlusion pattern."},{"speaker":"Attending","german":"Should reperfusion wait for biomarker confirmation?","translation_en":"No. Treatment of confirmed STEMI must not be delayed for troponin."},{"speaker":"Resident","german":"I will activate the primary PCI pathway while providing antiplatelet and anticoagulant therapy as appropriate.","translation_en":"Rapid flow restoration limits infarct size."}]'::jsonb, 'Cardiology', 'IHD'),
('Dynamic Troponin Elevation', 'Distinguishing NSTEMI from chronic myocardial injury.', 'advanced', 'medical', '[{"speaker":"Attending","german":"A patient with kidney disease has a mildly elevated troponin at baseline. What pattern supports acute MI?","translation_en":"A significant rise and/or fall with at least one value above the assay-specific 99th percentile plus evidence of ischemia."},{"speaker":"Resident","german":"A stable chronic elevation alone indicates myocardial injury but does not prove an acute plaque event.","translation_en":"Clinical context and serial measurements are essential."},{"speaker":"Attending","german":"If the ECG has no persistent ST elevation but ischemic symptoms and dynamic troponin are present, how is the syndrome classified?","translation_en":"NSTEMI."}]'::jsonb, 'Cardiology', 'IHD'),
('Inferior MI With Hypotension', 'Recognizing right-ventricular infarction and nitrate risk.', 'advanced', 'medical', '[{"speaker":"Resident","german":"A patient has ST elevation in II, III, and aVF with hypotension and clear lungs.","translation_en":"An inferior MI with possible right-ventricular involvement should be suspected."},{"speaker":"Attending","german":"Which additional lead is especially useful?","translation_en":"Right-sided lead V4R."},{"speaker":"Resident","german":"I should avoid nitrates because the right ventricle may be preload dependent.","translation_en":"Venodilation can precipitate severe hypotension."}]'::jsonb, 'Cardiology', 'IHD'),
('New Murmur Five Days After MI', 'Differentiating mechanical complications.', 'advanced', 'medical', '[{"speaker":"Attending","german":"Five days after MI, a patient develops shock and a new harsh holosystolic murmur at the lower left sternal border.","translation_en":"This strongly suggests ventricular septal rupture."},{"speaker":"Resident","german":"A left-to-right shunt should produce an oxygen-saturation step-up in the right ventricle.","translation_en":"The murmur location and shunt physiology help distinguish the lesion."},{"speaker":"Attending","german":"What alternative mechanical complication causes acute mitral regurgitation and pulmonary edema?","translation_en":"Papillary-muscle rupture."}]'::jsonb, 'Cardiology', 'IHD'),
('Pulseless Electrical Activity After MI', 'Recognizing free-wall rupture.', 'advanced', 'medical', '[{"speaker":"Resident","german":"One week after MI, a patient suddenly collapses with pulseless electrical activity and distended neck veins.","translation_en":"Free-wall rupture with hemopericardium and tamponade is likely."},{"speaker":"Attending","german":"Why is this timing important?","translation_en":"Macrophage-mediated tissue degradation makes the infarcted wall weakest during the first one to two weeks."},{"speaker":"Resident","german":"This is a catastrophic mechanical emergency requiring immediate resuscitation and surgical intervention.","translation_en":"The underlying cause must be treated, not merely the rhythm."}]'::jsonb, 'Cardiology', 'IHD'),
('Vasospastic Chest Pain', 'Managing variant angina.', 'core', 'medical', '[{"speaker":"Resident","german":"A young smoker has episodes of chest pain at night with transient ST elevation that resolves spontaneously.","translation_en":"The pattern suggests epicardial coronary vasospasm."},{"speaker":"Attending","german":"Which drugs are useful for prevention and relief?","translation_en":"Calcium-channel blockers and nitrates."},{"speaker":"Resident","german":"I will also identify triggers such as cocaine or other vasoconstrictive agents.","translation_en":"Trigger avoidance is part of treatment."}]'::jsonb, 'Cardiology', 'IHD'),
('Choosing PCI or CABG', 'Matching revascularization to coronary anatomy.', 'advanced', 'medical', '[{"speaker":"Attending","german":"A patient with diabetes has complex multivessel coronary disease despite optimal medical therapy.","translation_en":"This is a high-complexity anatomical pattern."},{"speaker":"Resident","german":"CABG often provides more durable and complete revascularization in this setting.","translation_en":"The choice depends on anatomy, comorbidities, surgical risk, and patient preference."},{"speaker":"Attending","german":"Which pattern is more likely to favor PCI?","translation_en":"Focal, less complex disease where catheter treatment can achieve adequate revascularization."}]'::jsonb, 'Cardiology', 'IHD'),
('Secondary Prevention After ACS', 'Reducing recurrent ischemic events.', 'core', 'medical', '[{"speaker":"Resident","german":"The patient has recovered after PCI for ACS. What long-term priorities should be addressed?","translation_en":"Antiplatelet therapy, intensive lipid lowering, blood-pressure and diabetes control, smoking cessation, and cardiac rehabilitation."},{"speaker":"Attending","german":"When are ACE inhibitors or ARBs especially valuable?","translation_en":"With reduced ejection fraction, anterior MI, hypertension, diabetes, or chronic kidney disease."},{"speaker":"Resident","german":"DAPT duration should be individualized according to bleeding and ischemic risk.","translation_en":"The default strategy may need shortening, de-escalation, or extension."}]'::jsonb, 'Cardiology', 'IHD');
INSERT INTO public.long_texts (title_de, title_en, body_de, translation_en, level, mode, chapter, lesson) VALUES
('Case Study: Chronic Exertional Angina', 'A fixed coronary stenosis limits flow reserve during exertion.', 'A 61-year-old patient with hypertension, diabetes, and dyslipidemia reports retrosternal pressure when walking rapidly uphill. The discomfort resolves within several minutes of rest. The resting ECG is normal, and high-sensitivity troponin is not elevated. Symptoms have been stable for six months.', 'Diagnosis and takeaway: This is typical angina within a chronic coronary syndrome. A stable plaque may permit adequate resting flow but prevent the increase in flow required during exertion. A normal resting ECG and normal troponin do not exclude stable coronary disease. Management combines risk-factor modification, high-intensity statin therapy, antiplatelet therapy when appropriate, antianginal treatment, and selective anatomical or functional testing.', 'core', 'medical', 'Cardiology', 'IHD'),
('Case Study: Anterior STEMI', 'Persistent anterior ST elevation requires immediate reperfusion.', 'A 58-year-old patient develops severe central chest pressure, diaphoresis, and nausea. The ECG shows persistent ST-segment elevation in V1 through V4. The first troponin result has not yet returned. Blood pressure is stable and there are no contraindications to antithrombotic therapy.', 'Diagnosis and takeaway: The ECG localizes a STEMI to the LAD territory. Reperfusion must not wait for troponin. Primary PCI is preferred when available promptly, accompanied by appropriate antiplatelet, anticoagulant, and high-intensity statin therapy. Delay allows necrosis to progress from the subendocardium toward the epicardium.', 'core', 'medical', 'Cardiology', 'IHD'),
('Case Study: NSTEMI With Dynamic Troponin', 'Dynamic biomarker change plus ischemia establishes myocardial infarction.', 'A 74-year-old patient presents with prolonged chest pressure and ST depression in lateral leads. High-sensitivity troponin is initially mildly elevated and rises substantially on repeat testing. There is no persistent ST elevation. The patient has recurrent pain despite initial therapy.', 'Diagnosis and takeaway: This is NSTEMI. The rise in troponin in an ischemic clinical context demonstrates acute necrosis. Recurrent pain places the patient in a higher-risk group and supports an early or immediate invasive strategy depending on the degree of instability. Treatment includes DAPT, parenteral anticoagulation, anti-ischemic therapy when safe, and early statin treatment.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Type 2 Myocardial Infarction', 'Severe supply-demand imbalance may cause infarction without plaque rupture.', 'A patient with profound anemia and sustained tachyarrhythmia develops chest discomfort and a dynamic rise in troponin. Coronary angiography does not reveal an acute thrombotic occlusion. The ECG shows diffuse ischemic changes rather than a focal persistent ST-elevation pattern.', 'Diagnosis and takeaway: The mechanism is consistent with type 2 myocardial infarction caused by oxygen supply-demand imbalance. Management focuses on correcting anemia, controlling the tachyarrhythmia, restoring perfusion, and evaluating underlying coronary disease. The case differs from type 1 MI, which is caused by acute atherothrombosis.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Right-Ventricular Infarction', 'Inferior MI with hypotension and clear lungs suggests RV involvement.', 'A 65-year-old patient has severe chest pain with ST elevation in leads II, III, and aVF. The blood pressure is 78/50 mmHg, jugular venous pressure is elevated, and the lungs are clear. Right-sided lead V4R also shows ST elevation.', 'Diagnosis and takeaway: This is an inferior STEMI with right-ventricular infarction, commonly caused by proximal RCA occlusion. The right ventricle is preload dependent, so nitrates and other preload-reducing drugs can worsen hypotension. Immediate reperfusion and careful hemodynamic support are required.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Papillary-Muscle Rupture', 'Acute mitral regurgitation several days after MI is a surgical emergency.', 'Four days after an inferior myocardial infarction, a patient suddenly develops severe dyspnea, pulmonary edema, hypotension, and a new systolic murmur. Echocardiography reveals a flail mitral leaflet and severe acute mitral regurgitation.', 'Diagnosis and takeaway: The likely lesion is posteromedial papillary-muscle rupture. This muscle is vulnerable because it usually has a single blood supply from the PDA. The complication occurs during the period of macrophage-mediated tissue weakening and requires urgent stabilization and surgical management.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Ventricular Septal Rupture', 'A new lower-left-sternal-border murmur after MI indicates a mechanical shunt until proven otherwise.', 'Five days after a large anterior infarction, a patient develops sudden shock. Examination reveals a harsh holosystolic murmur at the lower left sternal border with a palpable thrill. Right-heart catheterization shows a step-up in oxygen saturation in the right ventricle.', 'Diagnosis and takeaway: This is post-infarction ventricular septal rupture producing an acute left-to-right shunt. The timing corresponds to maximal myocardial weakness. Rapid diagnosis, hemodynamic stabilization, and urgent surgical evaluation are essential.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Left-Ventricular Free-Wall Rupture', 'Tamponade and PEA after MI suggest catastrophic wall rupture.', 'Ten days after myocardial infarction, a patient suddenly loses consciousness. The monitor shows organized electrical activity, but no pulse is present. Bedside ultrasound demonstrates a large pericardial effusion with tamponade physiology.', 'Diagnosis and takeaway: The most likely cause is left-ventricular free-wall rupture with hemopericardium. Macrophage clearance of necrotic tissue weakens the infarcted wall before collagen scar formation. This condition causes pulseless electrical activity and requires immediate resuscitation and emergency surgical treatment.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Posterior Myocardial Infarction', 'Reciprocal anterior changes may conceal a posterior occlusion.', 'A patient presents with prolonged ischemic chest pain. The standard ECG shows ST depression and tall dominant R waves in V1 through V3. Posterior leads V7 through V9 demonstrate ST elevation.', 'Diagnosis and takeaway: This is a posterior STEMI, often caused by PDA occlusion from the RCA or LCx depending on coronary dominance. Reciprocal anterior changes should trigger posterior-lead recording. Once confirmed, the patient requires the same urgent reperfusion pathway as other STEMI presentations.', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Case Study: Late Ventricular Aneurysm', 'A scarred aneurysmal segment causes late thrombotic and arrhythmic risk.', 'Several months after a large anterior MI, a patient has persistent ST elevation, reduced ejection fraction, and an outward-bulging dyskinetic apical segment on echocardiography. A mural thrombus is visualized within the abnormal chamber.', 'Diagnosis and takeaway: This is a true left-ventricular aneurysm formed from thinned scarred myocardium. It rarely ruptures because its wall is fibrotic, but it can cause heart failure, ventricular arrhythmias, persistent ST elevation, and systemic embolism from mural thrombus.', 'advanced', 'medical', 'Cardiology', 'IHD');
INSERT INTO public.grammar_exercises (question, options, correct_answer, explanation, topic, level, mode, chapter, lesson) VALUES
('Which artery supplies the anterior two-thirds of the interventricular septum?', '["Left anterior descending artery","Right coronary artery","Posterior descending artery","Left circumflex artery"]', 'Left anterior descending artery', 'The LAD supplies the anterior two-thirds of the septum, anterior LV wall, and usually the apex.', 'Coronary Anatomy', 'core', 'medical', 'Cardiology', 'IHD'),
('Coronary dominance is determined by the origin of which artery?', '["Posterior descending artery","Left main coronary artery","First diagonal artery","Acute marginal artery"]', 'Posterior descending artery', 'The coronary system is right-, left-, or codominant according to which artery gives rise to the PDA.', 'Coronary Anatomy', 'core', 'medical', 'Cardiology', 'IHD'),
('Why is the posteromedial papillary muscle especially vulnerable to infarction?', '["It usually has a single blood supply from the PDA","It receives no coronary blood supply","It is supplied only during systole","It is supplied exclusively by the LAD and LCx together"]', 'It usually has a single blood supply from the PDA', 'Unlike the anterolateral papillary muscle, the posteromedial muscle generally lacks dual arterial supply.', 'Coronary Anatomy', 'core', 'medical', 'Cardiology', 'IHD'),
('Left-ventricular coronary perfusion occurs predominantly during which phase?', '["Diastole","Early systole","Isovolumetric contraction only","Atrial systole only"]', 'Diastole', 'Systolic myocardial contraction compresses intramyocardial vessels, so LV perfusion is greatest during diastole.', 'Perfusion Physiology', 'core', 'medical', 'Cardiology', 'IHD'),
('Which variable both increases myocardial oxygen demand and reduces coronary supply time?', '["Tachycardia","Bradycardia","Reduced contractility","Lower afterload"]', 'Tachycardia', 'A rapid heart rate increases the number of contractions and shortens diastole.', 'Oxygen Supply and Demand', 'core', 'medical', 'Cardiology', 'IHD'),
('Which three variables are the principal determinants of myocardial oxygen demand?', '["Heart rate, contractility, and wall stress","Hemoglobin, oxygen saturation, and coronary anatomy","Preload, sodium concentration, and respiratory rate","Platelet count, INR, and fibrinogen"]', 'Heart rate, contractility, and wall stress', 'These are the major drivers of myocardial oxygen consumption.', 'Oxygen Supply and Demand', 'core', 'medical', 'Cardiology', 'IHD'),
('Which condition can provoke ischemia by reducing arterial oxygen content despite patent coronaries?', '["Severe anemia","Mild hypercalcemia","Isolated hypernatremia","First-degree AV block"]', 'Severe anemia', 'Anemia reduces oxygen delivery and may produce supply-demand ischemia.', 'Oxygen Supply and Demand', 'core', 'medical', 'Cardiology', 'IHD'),
('Which feature is most characteristic of a vulnerable atherosclerotic plaque?', '["Thin fibrous cap with a large necrotic core","Thick cap with a small lipid core","Complete absence of inflammatory cells","Dense calcification without a lipid core in every case"]', 'Thin fibrous cap with a large necrotic core', 'Vulnerable plaques have intense inflammation, a large necrotic core, and a thin rupture-prone cap.', 'Atherosclerosis', 'core', 'medical', 'Cardiology', 'IHD'),
('What is a foam cell?', '["A macrophage filled with modified lipid","A platelet coated with fibrin","A necrotic cardiomyocyte","A smooth-muscle cell without lipid"]', 'A macrophage filled with modified lipid', 'Macrophages take up modified LDL through scavenger receptors and become foam cells.', 'Atherosclerosis', 'core', 'medical', 'Cardiology', 'IHD'),
('Which event directly exposes tissue factor and the necrotic core to blood?', '["Plaque rupture","Stable fibrous-cap thickening","Coronary vasodilation","Myocardial hypertrophy"]', 'Plaque rupture', 'A cap tear exposes highly thrombogenic plaque contents and triggers thrombosis.', 'Atherosclerosis', 'core', 'medical', 'Cardiology', 'IHD'),
('Irreversible myocardial injury classically begins in which region?', '["Subendocardium","Epicardium","Pericardium","Right atrium"]', 'Subendocardium', 'The subendocardium is most vulnerable and necrosis progresses outward with persistent ischemia.', 'MI Pathology', 'core', 'medical', 'Cardiology', 'IHD'),
('What is the major complication during the first 24 hours after MI?', '["Malignant ventricular arrhythmia","Dense collagen scar","Dressler syndrome","True ventricular aneurysm formation"]', 'Malignant ventricular arrhythmia', 'VF and VT are early complications and major causes of sudden prehospital death.', 'MI Timeline', 'core', 'medical', 'Cardiology', 'IHD'),
('Which inflammatory cell predominates one to three days after MI?', '["Neutrophil","Macrophage","Plasma cell","Eosinophil"]', 'Neutrophil', 'Acute neutrophilic inflammation accompanies extensive coagulative necrosis during this period.', 'MI Timeline', 'core', 'medical', 'Cardiology', 'IHD'),
('Why is the infarcted myocardium especially vulnerable to rupture between approximately 3 and 14 days?', '["Macrophages remove necrotic tissue before strong scar formation","The fibrous scar is fully mature","Neutrophils increase collagen strength","The epicardium becomes hypertrophied"]', 'Macrophages remove necrotic tissue before strong scar formation', 'Tissue degradation precedes adequate collagen deposition, leaving the wall mechanically weak.', 'MI Timeline', 'core', 'medical', 'Cardiology', 'IHD'),
('Which late complication is associated with a mature infarct scar?', '["True ventricular aneurysm","Acute papillary-muscle rupture on day 1","Hyperacute T waves","Plaque erosion at the original coronary lesion only"]', 'True ventricular aneurysm', 'A thinned fibrotic scar may bulge outward and produce aneurysm, thrombus, and arrhythmia.', 'MI Timeline', 'core', 'medical', 'Cardiology', 'IHD'),
('Which three findings define typical angina?', '["Retrosternal discomfort, exertional provocation, and relief with rest or nitrates","Pleuritic pain, fever, and cough","Positional pain, friction rub, and diffuse ST elevation","Syncope, palpitations, and bradycardia"]', 'Retrosternal discomfort, exertional provocation, and relief with rest or nitrates', 'All three classic features are required for typical angina.', 'Chronic Coronary Syndrome', 'core', 'medical', 'Cardiology', 'IHD'),
('A patient meets two of the three classic angina criteria. How is the pain classified?', '["Atypical angina","Typical angina","Non-cardiac pain by definition","STEMI"]', 'Atypical angina', 'Atypical angina meets two criteria; typical angina meets all three.', 'Chronic Coronary Syndrome', 'core', 'medical', 'Cardiology', 'IHD'),
('Which presentation is a recognized anginal equivalent?', '["Exertional dyspnea","Isolated pruritus","Painless hematuria","Chronic unilateral leg swelling"]', 'Exertional dyspnea', 'Dyspnea, fatigue, nausea, and epigastric discomfort may represent ischemia without chest pain.', 'Clinical Presentation', 'core', 'medical', 'Cardiology', 'IHD'),
('Which CCS class describes angina at rest or with minimal activity?', '["Class IV","Class I","Class II","Class III"]', 'Class IV', 'CCS class IV represents severe limitation, with symptoms during minimal activity or at rest.', 'Clinical Assessment', 'core', 'medical', 'Cardiology', 'IHD'),
('Which statement about the resting ECG in stable angina is correct?', '["It may be completely normal between episodes","It always shows ST elevation","It always shows pathologic Q waves","It is unnecessary in all patients"]', 'It may be completely normal between episodes', 'A normal resting ECG does not exclude chronic coronary disease.', 'Diagnosis', 'core', 'medical', 'Cardiology', 'IHD'),
('Which biomarker is usually normal in stable chronic coronary syndrome?', '["Cardiac troponin","LDL cholesterol","Hemoglobin A1c","C-reactive protein"]', 'Cardiac troponin', 'Troponin indicates myocardial injury and is not a screening marker for stable angina.', 'Diagnosis', 'core', 'medical', 'Cardiology', 'IHD'),
('Which exercise-ECG change suggests inducible ischemia?', '["Horizontal or downsloping ST depression","Shortened PR interval","Isolated U-wave inversion","Progressive QRS narrowing"]', 'Horizontal or downsloping ST depression', 'Exercise-induced horizontal or downsloping ST depression supports myocardial ischemia.', 'Stress Testing', 'core', 'medical', 'Cardiology', 'IHD'),
('What does a reversible defect on nuclear perfusion imaging represent?', '["Inducible ischemia","Dense fixed scar","Pericardial inflammation","Normal coronary reserve"]', 'Inducible ischemia', 'A defect appearing during stress but resolving at rest indicates reversible ischemia.', 'Imaging', 'core', 'medical', 'Cardiology', 'IHD'),
('What does a fixed perfusion defect most commonly indicate?', '["Myocardial scar","Transient vasospasm only","Normal myocardium","Acute pericarditis"]', 'Myocardial scar', 'A defect present both at rest and stress is consistent with infarcted or scarred myocardium.', 'Imaging', 'core', 'medical', 'Cardiology', 'IHD'),
('Which test offers non-invasive anatomical visualization of coronary plaque and lumen?', '["Coronary CT angiography","Exercise ECG alone","Holter monitoring","Chest radiography"]', 'Coronary CT angiography', 'CCTA provides high-resolution anatomical coronary imaging.', 'Imaging', 'core', 'medical', 'Cardiology', 'IHD'),
('Which test is the reference standard for defining coronary anatomy?', '["Invasive coronary angiography","Resting ECG","Serum CK-MB","Chest ultrasound"]', 'Invasive coronary angiography', 'Catheter angiography directly visualizes the coronary lumen and supports intervention.', 'Imaging', 'core', 'medical', 'Cardiology', 'IHD'),
('What is the purpose of fractional flow reserve?', '["To assess whether an intermediate stenosis is physiologically significant","To measure left-atrial pressure only","To identify ventricular arrhythmia","To grade mitral regurgitation"]', 'To assess whether an intermediate stenosis is physiologically significant', 'FFR uses pressure measurements across a lesion to evaluate its impact on flow.', 'Coronary Physiology', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Which drug class is generally first-line for symptom relief in stable exertional angina?', '["Beta-blockers","Fibrinolytics","P2Y12 inhibitors alone","Thrombolytics for daily use"]', 'Beta-blockers', 'Beta-blockers lower heart rate and contractility and prolong diastolic perfusion.', 'Chronic Coronary Management', 'core', 'medical', 'Cardiology', 'IHD'),
('How do nitrates principally reduce myocardial oxygen demand?', '["By venodilation and preload reduction","By increasing contractility","By increasing afterload","By accelerating heart rate"]', 'By venodilation and preload reduction', 'Reduced venous return lowers ventricular radius, wall stress, and oxygen demand.', 'Chronic Coronary Management', 'core', 'medical', 'Cardiology', 'IHD'),
('Which antianginal drug has little direct effect on heart rate or blood pressure?', '["Ranolazine","Metoprolol","Diltiazem","Sublingual nitroglycerin"]', 'Ranolazine', 'Ranolazine reduces intracellular calcium-related diastolic tension without major hemodynamic effects.', 'Chronic Coronary Management', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Which coronary pattern generally favors CABG over PCI?', '["Left-main or complex multivessel disease","A single focal uncomplicated stenosis in every patient","Normal coronary arteries","Transient vasospasm without stenosis"]', 'Left-main or complex multivessel disease', 'CABG often provides durable complete revascularization for complex anatomy.', 'Revascularization', 'core', 'medical', 'Cardiology', 'IHD'),
('Variant angina is caused by what mechanism?', '["Transient epicardial coronary vasospasm","Fixed severe anemia","Permanent AV block","Papillary-muscle rupture"]', 'Transient epicardial coronary vasospasm', 'Prinzmetal angina produces episodic ischemia from dynamic vasoconstriction.', 'Special Syndromes', 'core', 'medical', 'Cardiology', 'IHD'),
('Which treatment is central to prevention of vasospastic angina?', '["Calcium-channel blocker","Nonselective beta-blocker","Fibrinolytic therapy","Digoxin"]', 'Calcium-channel blocker', 'CCBs reduce coronary vasospasm; nitrates are also useful.', 'Special Syndromes', 'core', 'medical', 'Cardiology', 'IHD'),
('What does INOCA describe?', '["Ischemia with non-obstructive coronary arteries","Infarction with complete left-main occlusion","Isolated non-cardiac chest pain","Infective endocarditis with normal arteries"]', 'Ischemia with non-obstructive coronary arteries', 'Microvascular dysfunction or vasospasm can produce ischemia without major epicardial obstruction.', 'Special Syndromes', 'advanced', 'medical', 'Cardiology', 'IHD'),
('What is the first essential test in suspected ACS?', '["Rapid 12-lead ECG","Elective stress test","Cardiac MRI before examination","Routine outpatient lipid panel only"]', 'Rapid 12-lead ECG', 'The ECG rapidly identifies patients who require an immediate STEMI reperfusion pathway.', 'ACS Diagnosis', 'core', 'medical', 'Cardiology', 'IHD'),
('What should be done when the first ECG is non-diagnostic but ischemic symptoms continue?', '["Repeat serial ECGs","Exclude ACS immediately","Wait one week before reassessment","Perform exercise testing during active pain"]', 'Repeat serial ECGs', 'Dynamic ischemic changes may appear on subsequent tracings.', 'ACS Diagnosis', 'core', 'medical', 'Cardiology', 'IHD'),
('Which biomarker pattern supports acute MI?', '["A rise and/or fall in troponin with at least one value above the 99th percentile plus ischemic evidence","A stable chronic troponin elevation alone","Normal serial troponins with no ischemia","An isolated high LDL level"]', 'A rise and/or fall in troponin with at least one value above the 99th percentile plus ischemic evidence', 'Acute MI requires dynamic injury biomarkers interpreted in an ischemic clinical context.', 'ACS Diagnosis', 'advanced', 'medical', 'Cardiology', 'IHD'),
('A diagnostic STEMI is present but troponin is pending. What is the correct action?', '["Begin the reperfusion pathway without waiting","Delay PCI until troponin peaks","Discharge if the first troponin is normal","Perform an outpatient stress test first"]', 'Begin the reperfusion pathway without waiting', 'STEMI is an ECG-based emergency and treatment must not wait for biomarker confirmation.', 'ACS Diagnosis', 'core', 'medical', 'Cardiology', 'IHD'),
('Which feature distinguishes unstable angina from NSTEMI?', '["Absence of biomarker-defined necrosis","Persistent ST elevation","Presence of a ventricular aneurysm","Obligatory cardiogenic shock"]', 'Absence of biomarker-defined necrosis', 'Troponin remains negative in unstable angina but rises dynamically in NSTEMI.', 'ACS Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('Which finding defines NSTEMI?', '["Dynamic troponin elevation with ischemia and no persistent ST elevation","Persistent ST elevation with normal troponin forever","Negative troponin and no ischemic symptoms","Only a fixed perfusion defect"]', 'Dynamic troponin elevation with ischemia and no persistent ST elevation', 'NSTEMI is biomarker-positive myocardial infarction without the persistent ST elevation of STEMI.', 'ACS Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('What is the usual mechanism of STEMI?', '["Acute complete or near-complete epicardial coronary occlusion","Stable fixed stenosis with no thrombosis","Isolated sinus bradycardia","Chronic pericardial inflammation"]', 'Acute complete or near-complete epicardial coronary occlusion', 'A fully occlusive thrombus causes severe transmural ischemia and persistent ST elevation.', 'ACS Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('Which medication should be loaded promptly in most ACS patients unless contraindicated?', '["Aspirin","Warfarin only","Digoxin","Adenosine"]', 'Aspirin', 'Aspirin rapidly inhibits platelet thromboxane production and forms the foundation of ACS antiplatelet therapy.', 'ACS Management', 'core', 'medical', 'Cardiology', 'IHD'),
('DAPT combines aspirin with which class?', '["P2Y12 inhibitor","ACE inhibitor","Loop diuretic","Calcium supplement"]', 'P2Y12 inhibitor', 'Clopidogrel, prasugrel, and ticagrelor inhibit the platelet P2Y12 receptor.', 'ACS Management', 'core', 'medical', 'Cardiology', 'IHD'),
('What is the purpose of parenteral anticoagulation in ACS?', '["To limit fibrin propagation","To dissolve all plaques permanently","To increase platelet aggregation","To replace reperfusion in STEMI"]', 'To limit fibrin propagation', 'Anticoagulation reduces further clot growth during the acute phase.', 'ACS Management', 'advanced', 'medical', 'Cardiology', 'IHD'),
('In which setting are nitrates contraindicated?', '["Right-ventricular infarction with preload dependence","Stable hypertension with normal perfusion","Chronic dyslipidemia","Remote history of smoking alone"]', 'Right-ventricular infarction with preload dependence', 'Venodilation can cause profound hypotension in RV infarction.', 'ACS Management', 'core', 'medical', 'Cardiology', 'IHD'),
('What is the preferred reperfusion treatment for STEMI when promptly available?', '["Primary PCI","Elective exercise testing","Long-term nitrate monotherapy","Observation without antithrombotic therapy"]', 'Primary PCI', 'Primary PCI mechanically restores coronary flow and is preferred when it can be delivered rapidly.', 'Reperfusion', 'core', 'medical', 'Cardiology', 'IHD'),
('When is fibrinolysis considered for STEMI?', '["Early presentation when timely PCI is unavailable and no contraindication exists","Any time after several weeks","Only after successful PCI","For unstable angina with negative troponin"]', 'Early presentation when timely PCI is unavailable and no contraindication exists', 'Fibrinolysis is an alternative reperfusion strategy for eligible early STEMI patients.', 'Reperfusion', 'core', 'medical', 'Cardiology', 'IHD'),
('Which NSTE-ACS feature supports an immediate invasive strategy?', '["Cardiogenic shock","Stable symptoms resolved months ago","Normal serial troponins and ECGs","Isolated hyperlipidemia"]', 'Cardiogenic shock', 'Shock, refractory pain, instability, malignant arrhythmia, or mechanical complications require urgent angiography.', 'NSTE-ACS', 'advanced', 'medical', 'Cardiology', 'IHD'),
('What causes type 1 myocardial infarction?', '["Acute atherothrombosis after plaque disruption","Anemia without thrombosis","Sustained tachycardia without plaque rupture","CABG surgery"]', 'Acute atherothrombosis after plaque disruption', 'Type 1 MI is the spontaneous plaque rupture or erosion infarction.', 'MI Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('What causes type 2 myocardial infarction?', '["Oxygen supply-demand imbalance without acute atherothrombosis","Acute stent thrombosis only","CABG-related injury","Plaque rupture in every case"]', 'Oxygen supply-demand imbalance without acute atherothrombosis', 'Anemia, hypoxemia, hypotension, tachyarrhythmia, or severe hypertension may produce type 2 MI.', 'MI Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('Which MI type is associated with PCI?', '["Type 4","Type 1","Type 2","Type 5"]', 'Type 4', 'Type 4 includes PCI-related infarction and stent-associated events.', 'MI Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('Which MI type is associated with CABG?', '["Type 5","Type 1","Type 2","Type 3"]', 'Type 5', 'Type 5 MI occurs in relation to coronary bypass surgery.', 'MI Classification', 'core', 'medical', 'Cardiology', 'IHD'),
('Which leads localize an inferior STEMI?', '["II, III, and aVF","V1 and V2 only","I and aVL only","V7 through V9 only"]', 'II, III, and aVF', 'Inferior-wall infarction produces ST elevation in the inferior limb leads.', 'ECG Localization', 'core', 'medical', 'Cardiology', 'IHD'),
('Which lead is especially useful for detecting right-ventricular infarction?', '["V4R","aVR only","V6R only","V9"]', 'V4R', 'Right-sided V4R is the key additional lead in suspected RV infarction.', 'ECG Localization', 'core', 'medical', 'Cardiology', 'IHD'),
('Which standard-ECG pattern suggests posterior MI?', '["ST depression with tall R waves in V1 to V3","Diffuse PR depression","Short PR interval with delta wave","Progressive PR prolongation"]', 'ST depression with tall R waves in V1 to V3', 'These reciprocal anterior changes should prompt posterior leads V7 to V9.', 'ECG Localization', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Troponin remains elevated for approximately how long according to the source?', '["7 to 10 days","Only 30 minutes","Less than 2 hours","Exactly one month in every patient"]', '7 to 10 days', 'Its prolonged elevation makes troponin useful for late diagnosis but less useful for early reinfarction.', 'Biomarkers', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Why can CK-MB help diagnose early reinfarction?', '["It returns toward normal within about 48 hours","It remains elevated for several months","It is never elevated after the first MI","It directly measures coronary flow"]', 'It returns toward normal within about 48 hours', 'A new rise after normalization may indicate reinfarction.', 'Biomarkers', 'advanced', 'medical', 'Cardiology', 'IHD'),
('A new systolic murmur with acute pulmonary edema two to seven days after inferior MI suggests what?', '["Papillary-muscle rupture","Dressler syndrome","True ventricular aneurysm","Stable angina"]', 'Papillary-muscle rupture', 'Posteromedial papillary-muscle rupture causes acute severe mitral regurgitation and shock.', 'MI Complications', 'core', 'medical', 'Cardiology', 'IHD'),
('A new harsh holosystolic murmur at the lower left sternal border several days after MI suggests what?', '["Ventricular septal rupture","Papillary-muscle rupture","Dressler syndrome","Aortic dissection"]', 'Ventricular septal rupture', 'Septal rupture produces a left-to-right shunt and a characteristic murmur.', 'MI Complications', 'core', 'medical', 'Cardiology', 'IHD'),
('Sudden PEA with tamponade one week after MI most strongly suggests what?', '["Left-ventricular free-wall rupture","Stable ventricular aneurysm","Chronic mitral stenosis","Unstable angina"]', 'Left-ventricular free-wall rupture', 'Free-wall rupture causes hemopericardium, tamponade, and rapid circulatory collapse.', 'MI Complications', 'core', 'medical', 'Cardiology', 'IHD'),
('When does Dressler syndrome typically occur?', '["Several weeks after MI","Within the first five minutes","Only before MI","Exactly one day after every MI"]', 'Several weeks after MI', 'Dressler syndrome is delayed autoimmune pericarditis, commonly appearing 2 to 10 weeks after infarction.', 'MI Complications', 'core', 'medical', 'Cardiology', 'IHD'),
('Which feature is associated with a true ventricular aneurysm?', '["Persistent ST elevation and mural thrombus risk","High risk of acute rupture in every case","Immediate normalization of LV function","Complete absence of arrhythmia risk"]', 'Persistent ST elevation and mural thrombus risk', 'A scarred aneurysmal segment may produce dyskinesia, thrombus, heart failure, and arrhythmias.', 'MI Complications', 'advanced', 'medical', 'Cardiology', 'IHD'),
('Which therapy is foundational for secondary lipid prevention after ACS?', '["High-intensity or maximally tolerated statin","Low-dose fibrinolytic indefinitely","Adenosine","Routine digoxin"]', 'High-intensity or maximally tolerated statin', 'Statins lower LDL, reduce inflammation, and stabilize plaque.', 'Secondary Prevention', 'core', 'medical', 'Cardiology', 'IHD'),
('Which patients particularly benefit from ACE inhibitor or ARB therapy after MI?', '["Those with reduced EF, anterior MI, hypertension, diabetes, or CKD","Only patients with normal blood pressure and no risk factors","Only patients with vasospastic angina","Only patients with isolated right bundle-branch block"]', 'Those with reduced EF, anterior MI, hypertension, diabetes, or CKD', 'RAAS blockade limits remodeling and provides vascular and renal protection in these groups.', 'Secondary Prevention', 'core', 'medical', 'Cardiology', 'IHD'),
('When should primary-prevention ICD eligibility generally be reassessed after MI according to the source?', '["After at least 40 days, with additional recovery time after revascularization","During the first hour of every MI","Only ten years later","Before ejection fraction is measured"]', 'After at least 40 days, with additional recovery time after revascularization', 'Early ventricular dysfunction may improve, so device decisions are deferred until recovery and medical optimization.', 'Device Therapy', 'advanced', 'medical', 'Cardiology', 'IHD'),
('What is a major benefit of structured cardiac rehabilitation?', '["Improved functional capacity and reduced recurrent morbidity","Immediate dissolution of coronary plaque","Guaranteed elimination of all future MI risk","Replacement of antiplatelet therapy"]', 'Improved functional capacity and reduced recurrent morbidity', 'Rehabilitation integrates exercise, education, risk reduction, and psychosocial support.', 'Secondary Prevention', 'core', 'medical', 'Cardiology', 'IHD');
